"use client";

import { useRef, useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Slider } from "@/components/ui/slider";
import { Loader2, Sparkles, Image, Upload, X, Copy, Check, AlertCircle, Wand2, Download } from "lucide-react";

// Image generation templates
const IMAGE_TEMPLATES = {
  product_white: {
    name: "Product Studio (White Background)",
    prompt: "Professional product photography, pure white background, even studio lighting, high resolution, 4K, sharp focus, no shadows, isolated object",
    negativePrompt: "shadow, gradient background, colored background, text, watermark, logo, reflection, surface",
  },
  product_lifestyle: {
    name: "Lifestyle Scene",
    prompt: "Lifestyle product photography, natural lighting, modern home/office setting, depth of field, warm ambiance, realistic context, authentic use case",
    negativePrompt: "studio background, white background, artificial lighting, fake, plastic look",
  },
  product_macro: {
    name: "Macro Details",
    prompt: "Macro close-up product photography, extreme detail, texture visible, shallow depth of field, professional lighting, sharp focus on surface details",
    negativePrompt: "blurry, out of focus, wide shot, full product",
  },
  product_technical: {
    name: "Technical / Blueprint",
    prompt: "Technical product rendering, isometric view, blueprint style, clean lines, engineering drawing aesthetic, white background with subtle grid",
    negativePrompt: "realistic, shadow, texture, rough, organic",
  },
  product_color_variation: {
    name: "Color Variation",
    prompt: "Product in [COLOR] color, matte finish, same angle and lighting as original, consistent perspective, realistic material rendering",
    negativePrompt: "different angle, different lighting, distorted, warped",
  },
};

type TemplateKey = keyof typeof IMAGE_TEMPLATES;

interface AIImageStudioProps {
  // Optional: existing products for context, but not required
  products?: Array<{ slug: string; name: string; description?: string }>;
}

export function AIImageStudio({ products = [] }: AIImageStudioProps) {
  // Core state
  const [inputImage, setInputImage] = useState<string | null>(null);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<"upload" | "url">("upload");
  
  // Template & customization state
  const [selectedTemplate, setSelectedTemplate] = useState<TemplateKey>("product_white");
  const [customPrompt, setCustomPrompt] = useState("");
  const [useCustomPrompt, setUseCustomPrompt] = useState(false);
  const [negativePrompt, setNegativePrompt] = useState("");
  const [imageSize, setImageSize] = useState<"1024x1024" | "1792x1024" | "1024x1792">("1024x1024");
  const [imageQuality, setImageQuality] = useState<"standard" | "hd">("standard");
  const [colorOverride, setColorOverride] = useState("");
  
  // Additional settings
  const [imageUrl, setImageUrl] = useState("");
  const [remixInstructions, setRemixInstructions] = useState("");
  const [generationMode, setGenerationMode] = useState<"from-scratch" | "remix">("from-scratch");
  
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Handle image upload
  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 10 * 1024 * 1024) {
      setError("Image too large. Max 10MB.");
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      setInputImage(reader.result as string);
      setError(null);
    };
    reader.onerror = () => setError("Failed to read image");
    reader.readAsDataURL(file);
  };

  const clearImage = () => {
    setInputImage(null);
    setGeneratedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  // Build the final prompt based on template + customizations
  const buildPrompt = () => {
    if (useCustomPrompt && customPrompt) {
      let finalPrompt = customPrompt;
      if (colorOverride) {
        finalPrompt = finalPrompt.replace(/\[COLOR\]/g, colorOverride);
      }
      return finalPrompt;
    }

    let templatePrompt = IMAGE_TEMPLATES[selectedTemplate].prompt;
    if (colorOverride && selectedTemplate === "product_color_variation") {
      templatePrompt = templatePrompt.replace(/\[COLOR\]/g, colorOverride);
    } else if (colorOverride) {
      templatePrompt = `${templatePrompt}, color: ${colorOverride}`;
    }
    
    if (remixInstructions && generationMode === "remix") {
      templatePrompt = `${templatePrompt}. Modified: ${remixInstructions}`;
    }
    
    return templatePrompt;
  };

  const getNegativePrompt = () => {
    if (useCustomPrompt && negativePrompt) return negativePrompt;
    return IMAGE_TEMPLATES[selectedTemplate].negativePrompt;
  };

  // Generate image from scratch (text-to-image)
  const generateFromScratch = async () => {
    setLoading(true);
    setError(null);
    setGeneratedImage(null);

    try {
      const prompt = buildPrompt();
      const negPrompt = getNegativePrompt();

      const res = await fetch("/api/ai/generate-image", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          prompt,
          negativePrompt: negPrompt,
          size: imageSize,
          quality: imageQuality,
        }),
      });

      const result = await res.json();
      if (!res.ok) throw new Error(result.error || "Generation failed");
      
      setGeneratedImage(result.imageUrl);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  // Remix existing image (image-to-image via vision + generation)
  const remixImage = async () => {
    if (!inputImage && !imageUrl) {
      setError("Please upload an image or provide a URL");
      return;
    }

    setLoading(true);
    setError(null);
    setGeneratedImage(null);

    try {
      const sourceImage = inputImage || imageUrl;
      const instructions = remixInstructions || (useCustomPrompt ? customPrompt : IMAGE_TEMPLATES[selectedTemplate].prompt);

      const res = await fetch("/api/ai-actions", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          action: 'remixImage',
          imageUrl: sourceImage,
          instructions,
          negativePrompt: getNegativePrompt(),
          size: imageSize,
        }),
      });

      const data = await res.json();
      // const data =
      //   {
      //     result: {
      //       generatedPrompt: "No longer using text prompt for remix",
      //       imageUrl: "data:image/png;base64,"
      //     }
      //   }
      // if (!res.ok) throw new Error(data.error || "Remix failed");

      // Handle different response structures
      let newImageUrl = data.result?.imageUrl;
      
      if (!newImageUrl) {
        console.error("Unexpected response structure:", data);
        throw new Error("No image URL in response");
      }
      
      console.log("New image URL:", newImageUrl.substring(0, 20));
      // Ensure base64 string is properly formatted (should start with data:image)
      if (newImageUrl.startsWith('data:image')) {
        setGeneratedImage(newImageUrl);
      } else if (newImageUrl.startsWith('/') || newImageUrl.startsWith('http')) {
        // It's a relative or absolute URL
        setGeneratedImage(newImageUrl);
      } else {
        // Might be raw base64 without prefix
        setGeneratedImage(`data:image/png;base64,${newImageUrl}`);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  const handleGenerate = () => {
    if (generationMode === "from-scratch") {
      generateFromScratch();
    } else {
      remixImage();
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    // Optional: add toast notification here
  };

  const downloadImage = () => {
    if (!generatedImage) return;
    const link = document.createElement("a");
    link.href = generatedImage;
    link.download = `ai-generated-${Date.now()}.png`;
    link.click();
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold">AI Image Studio</h2>
          <p className="text-sm text-muted-foreground">
            Generate realistic product images using templates or custom prompts
          </p>
        </div>
        <Sparkles className="h-8 w-8 text-primary" />
      </div>

      {/* Mode Selection */}
      <div className="flex gap-4">
        <Button
          variant={generationMode === "from-scratch" ? "default" : "outline"}
          onClick={() => setGenerationMode("from-scratch")}
          className="flex-1"
        >
          <Sparkles className="mr-2 h-4 w-4" />
          Generate
        </Button>
        <Button
          variant={generationMode === "remix" ? "default" : "outline"}
          onClick={() => setGenerationMode("remix")}
          className="flex-1"
        >
          <Wand2 className="mr-2 h-4 w-4" />
          Remix
        </Button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Left Panel - Inputs */}
        <Card>
          <CardHeader>
            <CardTitle>
              {generationMode === "from-scratch" ? "Generation Settings" : "Source Image & Settings"}
            </CardTitle>
            <CardDescription>
              {generationMode === "from-scratch" 
                ? "Describe what you want to generate" 
                : "Upload an image to remix with AI"}
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            {/* Image Upload (Remix mode only) */}
            {generationMode === "remix" && (
              <div className="space-y-2">
                <label className="text-sm font-medium">Source Image</label>
                <Tabs value={activeTab} onValueChange={(v) => setActiveTab(v as "upload" | "url")}>
                  <TabsList className="grid w-full grid-cols-2">
                    <TabsTrigger value="upload">Upload</TabsTrigger>
                    <TabsTrigger value="url">Image URL</TabsTrigger>
                  </TabsList>
                  <TabsContent value="upload" className="space-y-2">
                    <div className="flex items-center gap-2">
                      <Button
                        type="button"
                        variant="outline"
                        onClick={() => fileInputRef.current?.click()}
                        className="flex-1"
                      >
                        <Upload className="mr-2 h-4 w-4" />
                        Upload Image
                      </Button>
                      <input
                        ref={fileInputRef}
                        type="file"
                        accept="image/*"
                        onChange={handleImageUpload}
                        className="hidden"
                      />
                      {inputImage && (
                        <Button type="button" variant="ghost" onClick={clearImage}>
                          <X className="h-4 w-4" />
                        </Button>
                      )}
                    </div>
                    {inputImage && (
                      <img src={inputImage} alt="Source" className="max-h-32 rounded border object-contain" />
                    )}
                  </TabsContent>
                  <TabsContent value="url" className="space-y-2">
                    <Input
                      placeholder="https://example.com/product-image.jpg"
                      value={imageUrl}
                      onChange={(e) => setImageUrl(e.target.value)}
                    />
                  </TabsContent>
                </Tabs>
              </div>
            )}

            {/* Template or Custom Prompt Toggle */}
            <div className="space-y-2">
              <div className="flex items-center justify-between">
                <label className="text-sm font-medium">Prompt Mode</label>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setUseCustomPrompt(!useCustomPrompt)}
                >
                  {useCustomPrompt ? "Use Templates" : "Use Custom Prompt"}
                </Button>
              </div>

              {!useCustomPrompt ? (
                <>
                  <Select value={selectedTemplate} onValueChange={(v) => setSelectedTemplate(v as TemplateKey)}>
                    <SelectTrigger>
                      <SelectValue placeholder="Select a template" />
                    </SelectTrigger>
                    <SelectContent>
                      {Object.entries(IMAGE_TEMPLATES).map(([key, template]) => (
                        <SelectItem key={key} value={key}>
                          {template.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>

                  {/* Template preview */}
                  <div className="rounded-lg bg-secondary/50 p-3 text-sm">
                    <p className="font-medium text-xs mb-1">Template Prompt:</p>
                    <p className="text-muted-foreground">{IMAGE_TEMPLATES[selectedTemplate].prompt}</p>
                  </div>
                </>
              ) : (
                <>
                  <Textarea
                    placeholder="Describe the image you want to generate..."
                    value={customPrompt}
                    onChange={(e) => setCustomPrompt(e.target.value)}
                    rows={4}
                  />
                  <Input
                    placeholder="Negative prompt (optional) - things to avoid"
                    value={negativePrompt}
                    onChange={(e) => setNegativePrompt(e.target.value)}
                  />
                </>
              )}
            </div>

            {/* Color Override */}
            <div className="space-y-2">
              <label className="text-sm font-medium">Color Override (Optional)</label>
              <Input
                placeholder="e.g., Forest Green, Matte Black, Silver"
                value={colorOverride}
                onChange={(e) => setColorOverride(e.target.value)}
              />
            </div>

            {/* Remix Instructions (Remix mode only) */}
            {generationMode === "remix" && (
              <div className="space-y-2">
                <label className="text-sm font-medium">Remix Instructions</label>
                <Textarea
                  placeholder="What changes do you want? Examples: 'Change color to white with green letters', 'Add wood texture background', 'Make it look premium'"
                  value={remixInstructions}
                  onChange={(e) => setRemixInstructions(e.target.value)}
                  rows={3}
                />
              </div>
            )}

            {/* Image Settings */}
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-2">
                <label className="text-sm font-medium">Size</label>
                <Select value={imageSize} onValueChange={(v) => setImageSize(v as any)}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="1024x1024">Square (1024x1024)</SelectItem>
                    <SelectItem value="1792x1024">Landscape (1792x1024)</SelectItem>
                    <SelectItem value="1024x1792">Portrait (1024x1792)</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium">Quality</label>
                <Select value={imageQuality} onValueChange={(v) => setImageQuality(v as any)}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="standard">Standard</SelectItem>
                    <SelectItem value="hd">HD</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            {/* Generate Button */}
            <Button onClick={handleGenerate} disabled={loading} className="w-full" size="lg">
              {loading ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Generating...
                </>
              ) : (
                <>
                  <Sparkles className="mr-2 h-4 w-4" />
                  {generationMode === "from-scratch" ? "Generate Image" : "Remix Image"}
                </>
              )}
            </Button>

            {error && (
              <Alert variant="destructive">
                <AlertCircle className="h-4 w-4" />
                <AlertDescription>{error}</AlertDescription>
              </Alert>
            )}
          </CardContent>
        </Card>

        {/* Right Panel - Output */}
        <Card>
          <CardHeader>
            <CardTitle>Generated Image</CardTitle>
            <CardDescription>Your AI-generated result will appear here</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            {generatedImage ? (
              <>
                <div className="relative rounded-lg border bg-secondary/20 p-4 flex items-center justify-center">
                  <img 
                    src={generatedImage} 
                    alt="Generated" 
                    className="max-w-full rounded-lg shadow-lg" 
                    onError={(e) => {
                      console.error("Image failed to load:", generatedImage?.substring(0, 100));
                      e.currentTarget.style.display = 'none';
                    }}
                  />
                </div>
                <div className="flex gap-2">
                  <Button variant="outline" className="flex-1" onClick={() => copyToClipboard(generatedImage)}>
                    <Copy className="mr-2 h-4 w-4" />
                    Copy URL
                  </Button>
                  <Button variant="outline" className="flex-1" onClick={downloadImage}>
                    <Download className="mr-2 h-4 w-4" />
                    Download
                  </Button>
                </div>
              </>
            ) : (
              <div className="flex flex-col items-center justify-center min-h-[300px] text-center text-muted-foreground border-2 border-dashed rounded-lg">
                <Image className="h-12 w-12 mb-3 opacity-50" />
                <p>Your generated image will appear here</p>
                <p className="text-sm">Configure settings and click generate</p>
              </div>
            )}

            {/* Prompt used (for transparency) */}
            {generatedImage && (
              <div className="mt-4 pt-4 border-t">
                <p className="text-xs text-muted-foreground">
                  <strong>Prompt used:</strong> {buildPrompt()}
                </p>
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}
